const body = ($('Webhook').first().json.body) || {};
const types = ['encargo_profesional','contrato_cliente','contrato_gremio','acta_replanteo','acta_recepcion_provisional','acta_recepcion_definitiva','modificado_obra','renuncia_garantia','otros'];
if (!body.project_id) return [{ json: { valid:false, error:'project_id obligatorio' } }];
if (!body.contract_type || !types.includes(body.contract_type)) return [{ json: { valid:false, error:'contract_type debe ser uno de: '+types.join(', ') } }];
if (!body.parties || !Array.isArray(body.parties) || body.parties.length === 0) return [{ json: { valid:false, error:'parties debe ser array no vacio con [{role, name, dni?, email?, address?}]' } }];
return [{ json: {
  valid: true,
  project_id:    body.project_id,
  contract_type: body.contract_type,
  parties:       body.parties,
  scope:         (body.scope || '').toString().slice(0, 5000),
  amount_eur:    body.amount_eur ? Number(body.amount_eur) : null,
  expires_days:  body.expires_days ? Number(body.expires_days) : 30,
  notes:         (body.notes || '').toString().slice(0, 1000)
}}];

