INSERT INTO contracts (
  project_id, contract_type, title, parties, template_used, doc_url, doc_id, expires_at, amount_eur, scope, notes, status
) VALUES (
  $1::uuid, $2, $3, $4::jsonb, $5, $6, $7, $8::timestamptz, $9::numeric, $10, $11, 'draft'
)
RETURNING id, title, status, doc_url, expires_at;
